Add-Type -AssemblyName System.Drawing

$ProjectRoot = Split-Path -Parent $MyInvocation.MyCommand.Path
$OutDir = Join-Path $ProjectRoot "main"

$FontPath = "C:\Windows\Fonts\simhei.ttf"

# Extra glyph list generated by AirTouch UI Chinese scan.
# The latest p4_cn_glyphs_needed_v2n1_*.txt will be loaded automatically.
