function Get-UniqueCodes {
    $set = New-Object System.Collections.Generic.HashSet[int]

    for ($i = 32; $i -le 126; $i++) {
        [void]$set.Add($i)
    }

    foreach ($code in $ExtraCodes) {
        [void]$set.Add([int]$code)
    }

    if ($null -ne $GlyphFile -and (Test-Path $GlyphFile.FullName)) {
        Write-Host "Load extra glyphs from $($GlyphFile.FullName)"
        $glyphText = Get-Content $GlyphFile.FullName -Raw -Encoding UTF8
        foreach ($ch in $glyphText.ToCharArray()) {
            $code = [int][char]$ch
            if ($code -ge 32) {
                [void]$set.Add($code)
            }
        }
    } else {
        Write-Host "No extra glyph file found, use built-in ExtraCodes only."
    }

    $arr = New-Object System.Collections.Generic.List[int]
    foreach ($v in $set) {
        $arr.Add($v)
    }

    $arr.Sort()
    return $arr
}

function ByteArrayToC {
    param(
        [byte[]]$data,
        [int]$indent = 4
    )

    $lines = New-Object System.Collections.Generic.List[string]
    $line = " " * $indent
    $count = 0

    foreach ($b in $data) {
        $item = ("0x{0:x2}, " -f $b)
        $line += $item
        $count++

        if ($count -ge 12) {
            $lines.Add($line)
            $line = " " * $indent
            $count = 0
        }
    }

    if ($line.Trim().Length -gt 0) {
        $lines.Add($line)
    }

    return ($lines -join "`r`n")
}

function UInt16ArrayToC {
    param(
        [int[]]$data,
        [int]$indent = 4
    )

    $lines = New-Object System.Collections.Generic.List[string]
    $line = " " * $indent
    $count = 0

    foreach ($v in $data) {
        $item = ("0x{0:x}, " -f $v)
        $line += $item
        $count++

        if ($count -ge 10) {
            $lines.Add($line)
            $line = " " * $indent
            $count = 0
        }
    }

    if ($line.Trim().Length -gt 0) {
        $lines.Add($line)
    }

    return ($lines -join "`r`n")
}

function Generate-Font {
    param(
        [int]$Size,
        [string]$OutFile,
        [string]$VarName
    )

    $chars = Get-UniqueCodes

    $privateFonts = New-Object System.Drawing.Text.PrivateFontCollection
    $privateFonts.AddFontFile($FontPath)
    $family = $privateFonts.Families[0]

    $font = New-Object System.Drawing.Font(
        $family,
        [float]$Size,
        [System.Drawing.FontStyle]::Regular,
        [System.Drawing.GraphicsUnit]::Pixel
    )

    $bmpBytes = New-Object System.Collections.Generic.List[byte]
    $glyphDsc = New-Object System.Collections.Generic.List[string]

    $glyphDsc.Add("    {.bitmap_index = 0, .adv_w = 0, .box_w = 0, .box_h = 0, .ofs_x = 0, .ofs_y = 0}, /* id = 0 reserved */")

    $bitmapIndex = 0
    $glyphId = 1

    foreach ($code in $chars) {
        $ch = [string][char]$code

        $bmp = New-Object System.Drawing.Bitmap($Size, $Size, [System.Drawing.Imaging.PixelFormat]::Format32bppArgb)
        $g = [System.Drawing.Graphics]::FromImage($bmp)

        $g.Clear([System.Drawing.Color]::Black)
        $g.TextRenderingHint = [System.Drawing.Text.TextRenderingHint]::AntiAliasGridFit
        $g.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::HighQuality
        $g.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic
        $g.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::HighQuality

        $brush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::White)
        $format = [System.Drawing.StringFormat]::GenericTypographic
        $format.FormatFlags = $format.FormatFlags -bor [System.Drawing.StringFormatFlags]::NoClip

        $g.DrawString($ch, $font, $brush, 0, 0, $format)

        $rowBytes = New-Object System.Collections.Generic.List[byte]

        for ($y = 0; $y -lt $Size; $y++) {
            for ($x = 0; $x -lt $Size; $x += 2) {
                $p1 = $bmp.GetPixel($x, $y)
                $v1 = [int][Math]::Round($p1.R / 17.0)
                if ($v1 -lt 0) { $v1 = 0 }
                if ($v1 -gt 15) { $v1 = 15 }

                $v2 = 0
                if (($x + 1) -lt $Size) {
                    $p2 = $bmp.GetPixel($x + 1, $y)
                    $v2 = [int][Math]::Round($p2.R / 17.0)
                    if ($v2 -lt 0) { $v2 = 0 }
                    if ($v2 -gt 15) { $v2 = 15 }
                }

                $packed = (($v1 -shl 4) -bor $v2)
                [void]$rowBytes.Add([byte]$packed)
            }
        }

        foreach ($bb in $rowBytes) {
            [void]$bmpBytes.Add($bb)
        }

        $adv = $Size * 16
        $glyphDsc.Add("    {.bitmap_index = $bitmapIndex, .adv_w = $adv, .box_w = $Size, .box_h = $Size, .ofs_x = 0, .ofs_y = 0}, /* id = $glyphId U+$('{0:X4}' -f $code) */")

        $bitmapIndex += $rowBytes.Count

        $brush.Dispose()
        $g.Dispose()
        $bmp.Dispose()

        $glyphId++
    }

    $minCode = $chars[0]
    $offsets = New-Object System.Collections.Generic.List[int]
    foreach ($code in $chars) {
        $offsets.Add($code - $minCode)
    }

    $bitmapC = ByteArrayToC ([byte[]]$bmpBytes.ToArray())
    $offsetC = UInt16ArrayToC ([int[]]$offsets.ToArray())
    $glyphC = $glyphDsc -join "`r`n"

    $glyphCount = $chars.Count
    $rangeLen = $chars[$chars.Count - 1] - $minCode + 1
    $lineHeight = $Size
    $baseLine = 0

    $c = @"
#include "lvgl.h"

#ifndef LV_ATTRIBUTE_LARGE_CONST
#define LV_ATTRIBUTE_LARGE_CONST
#endif

static LV_ATTRIBUTE_LARGE_CONST const uint8_t ${VarName}_glyph_bitmap[] = {
$bitmapC
};

static const lv_font_fmt_txt_glyph_dsc_t ${VarName}_glyph_dsc[] = {
$glyphC
};

static const uint16_t ${VarName}_unicode_list_0[] = {
$offsetC
};

static const lv_font_fmt_txt_cmap_t ${VarName}_cmaps[] = {
    {
        .range_start = $minCode,
        .range_length = $rangeLen,
        .glyph_id_start = 1,
        .unicode_list = ${VarName}_unicode_list_0,
        .glyph_id_ofs_list = NULL,
        .list_length = $glyphCount,
        .type = LV_FONT_FMT_TXT_CMAP_SPARSE_TINY
    }
};

#if LVGL_VERSION_MAJOR == 8
static lv_font_fmt_txt_glyph_cache_t ${VarName}_cache;
#endif

#if LVGL_VERSION_MAJOR >= 8
static const lv_font_fmt_txt_dsc_t ${VarName}_font_dsc = {
#else
static lv_font_fmt_txt_dsc_t ${VarName}_font_dsc = {
#endif
    .glyph_bitmap = ${VarName}_glyph_bitmap,
    .glyph_dsc = ${VarName}_glyph_dsc,
    .cmaps = ${VarName}_cmaps,
    .kern_dsc = NULL,
    .kern_scale = 0,
    .cmap_num = 1,
    .bpp = 4,
    .kern_classes = 0,
    .bitmap_format = 0,
#if LVGL_VERSION_MAJOR == 8
    .cache = &${VarName}_cache
#endif
};

#if LVGL_VERSION_MAJOR >= 8
const lv_font_t $VarName = {
#else
lv_font_t $VarName = {
#endif
    .get_glyph_dsc = lv_font_get_glyph_dsc_fmt_txt,
    .get_glyph_bitmap = lv_font_get_bitmap_fmt_txt,
    .line_height = $lineHeight,
    .base_line = $baseLine,
#if !(LVGL_VERSION_MAJOR == 6 && LVGL_VERSION_MINOR == 0)
    .subpx = LV_FONT_SUBPX_NONE,
#endif
#if LV_VERSION_CHECK(7, 4, 0) || LVGL_VERSION_MAJOR >= 8
    .underline_position = -1,
    .underline_thickness = 1,
#endif
    .dsc = &${VarName}_font_dsc,
#if LV_VERSION_CHECK(8, 2, 0) || LVGL_VERSION_MAJOR >= 9
    .fallback = NULL,
#endif
    .user_data = NULL,
};
"@

    Set-Content -Path $OutFile -Value $c -Encoding UTF8

    Write-Host "Generated $OutFile chars=$glyphCount size=$Size"
}

Generate-Font -Size 20 -OutFile (Join-Path $OutDir "ui_font_cn_20.c") -VarName "ui_font_cn_20"
Generate-Font -Size 26 -OutFile (Join-Path $OutDir "ui_font_cn_26.c") -VarName "ui_font_cn_26"
Generate-Font -Size 32 -OutFile (Join-Path $OutDir "ui_font_cn_32.c") -VarName "ui_font_cn_32"

Write-Host "Done."


















